from functools import wraps
import json
import re

def pii_monitor(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        state = result.get('config', {}).get('state', {})
        state_json = json.dumps(state)

        PII_PATTERNS = [r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b']
        pii_matches = [m.group() for pattern in PII_PATTERNS for m in [re.search(pattern, state_json)] if m]

        if pii_matches:
            print(f'🚨 PII detected in state: {pii_matches}')

        return result
    return wrapper

# Usage
@pii_monitor
def run_agent(graph, input):
    return graph.invoke(input)

