from pydantic import BaseModel, field_validator
from typing import List, Optional
import re

class SanitizedMessage(BaseModel):
    role: str
    content: str

    @field_validator('content')
    @classmethod
    def redact_pii(cls, v):
        # Auto-redact common PII
        v = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', v)
        v = re.sub(r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b', '[PHONE]', v)
        return v

class SafeAgentState(BaseModel):
    messages: List[SanitizedMessage]
    customer_data: Optional[str] = None

    @field_validator('customer_data')
    @classmethod
    def sanitize_customer_data(cls, v):
        if v:
            v = re.sub(r'\b\d{3}-\d{2}-\d{4}\b', '[SSN]', v)
            v = re.sub(r'\b\d{5}(?:-|\s)?\d{4}\b', '[ZIP]', v)
        return v

# Use in LangGraph
class AgentState(TypedDict):
    state: SafeAgentState

